# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

def login_redirect(user):
    """
    Redirects users to their intended destination after authentication.

    Args:
        user: The authenticated user object.

    Returns:
        A flask redirect response to the user's intended destination.
    """

    # Get the user's intended destination from the session
    intended_destination = session.get('intended_destination')

    # If there is no intended destination, redirect to the home page
    if not intended_destination:
        return redirect(url_for('home'))

    # Otherwise, redirect to the user's intended destination
    return redirect(intended_destination)